mapper.delete:
DELETE FROM ranking_entry
WHERE university_id = #{universityId}
  AND source_id = #{sourceId}
  AND (subject_id = #{subjectId} OR (#{subjectId} IS NULL AND subject_id IS NULL))
  AND year = #{year}

mapper.select:
SELECT re.id, re.university_id, u.name_zh AS university_name_zh, u.name_en AS university_name_en, u.country, re.year, re.rank_display, re.rank_value, re.rank_delta, re.direction, re.subject_id, s.name_zh AS subject_name, re.source_id AS sourceId, rs.name_zh AS sourceName FROM ranking_entry re LEFT JOIN university u ON re.university_id = u.url_id LEFT JOIN subject s ON re.subject_id = s.id LEFT JOIN ranking_source rs ON re.source_id = rs.id WHERE re.deleted = 0 AND re.source_id = #{sourceId}
AND re.year = #{year}
ORDER BY re.year DESC, CASE WHEN re.rank_value IS NULL OR re.rank_value >= 9999 THEN 1 ELSE 0 END ASC, re.rank_value ASC, re.id ASC

SELECT re.id, re.university_id, u.name_zh AS university_name_zh, u.name_en AS university_name_en, u.country, re.year, re.rank_display, re.rank_value, re.rank_delta, re.direction, re.subject_id, s.name_zh AS subject_name, re.source_id AS sourceId, rs.name_zh AS sourceName FROM ranking_entry re LEFT JOIN university u ON re.university_id = u.url_id LEFT JOIN subject s ON re.subject_id = s.id LEFT JOIN ranking_source rs ON re.source_id = rs.id WHERE re.deleted = 0 AND re.university_id = #{universityId}
AND re.source_id = #{sourceId}
AND re.year = #{year}
AND re.subject_id IS NULL
ORDER BY re.year DESC, CASE WHEN re.rank_value IS NULL OR re.rank_value >= 9999 THEN 1 ELSE 0 END ASC, re.rank_value ASC, re.id ASC
